import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"archive/silicon/benchmarks.md","filePath":"archive/silicon/benchmarks.md"}'),i={name:"archive/silicon/benchmarks.md"};function l(r,t,o,d,p,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Vex&#39;s &quot;Silicon Native&quot; approach significantly reduces code complexity while maintaining or exceeding the performance of optimized C++/CUDA implementations.</p><h2 id="code-size-comparison" tabindex="-1">Code Size Comparison <a class="header-anchor" href="#code-size-comparison" aria-label="Permalink to &quot;Code Size Comparison&quot;">​</a></h2><p>The following table compares the Lines of Code (LOC) required to implement common high-performance algorithms in Vex versus a production-ready C++ implementation (including SIMD intrinsics and CUDA kernels).</p><table tabindex="0"><thead><tr><th style="text-align:left;">Algorithm</th><th style="text-align:left;">C/C++ (LOC)</th><th style="text-align:left;">Vex (LOC)</th><th style="text-align:left;">Reduction</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Matrix Multiply</strong></td><td style="text-align:left;">~1,510</td><td style="text-align:left;">1</td><td style="text-align:left;"><strong>99.9%</strong></td></tr><tr><td style="text-align:left;"><strong>Neural Network</strong></td><td style="text-align:left;">~5,500</td><td style="text-align:left;">15</td><td style="text-align:left;"><strong>99.7%</strong></td></tr><tr><td style="text-align:left;"><strong>AES-256</strong></td><td style="text-align:left;">~2,440</td><td style="text-align:left;">35</td><td style="text-align:left;"><strong>98.6%</strong></td></tr><tr><td style="text-align:left;"><strong>FFT (Radix-2)</strong></td><td style="text-align:left;">~2,200</td><td style="text-align:left;">25</td><td style="text-align:left;"><strong>98.9%</strong></td></tr><tr><td style="text-align:left;"><strong>Ray Tracer</strong></td><td style="text-align:left;">~4,500</td><td style="text-align:left;">60</td><td style="text-align:left;"><strong>98.7%</strong></td></tr></tbody></table><p><em>Note: C++ LOC estimates include boilerplate, headers, build scripts, memory management, and separate kernels for CPU/GPU.</em></p><h2 id="performance-targets" tabindex="-1">Performance Targets <a class="header-anchor" href="#performance-targets" aria-label="Permalink to &quot;Performance Targets&quot;">​</a></h2><p>Vex aims for <strong>Zero Overhead</strong> abstractions.</p><ul><li><strong>SIMD:</strong> Arrays allow auto-vectorization using LLVM&#39;s rigorous optimization pipeline. Vex&#39;s strict aliasing rules (via VUMM) allow more aggressive optimization than C++.</li><li><strong>GPU:</strong> Kernel generation is handled by the compiler, optimizing memory layout and access patterns automatically.</li><li><strong>Autograd:</strong> By fusing gradient computation with the forward pass (Fusion optimization), Vex reduces memory bandwidth usage compared to &quot;tape-based&quot; autograd systems (like PyTorch).</li></ul><h2 id="implementation-examples" tabindex="-1">Implementation Examples <a class="header-anchor" href="#implementation-examples" aria-label="Permalink to &quot;Implementation Examples&quot;">​</a></h2><h3 id="matrix-multiply" tabindex="-1">Matrix Multiply <a class="header-anchor" href="#matrix-multiply" aria-label="Permalink to &quot;Matrix Multiply&quot;">​</a></h3><p><strong>Vex:</strong></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let C = A &lt;*&gt; B</span></span></code></pre></div><p><strong>C++ / CUDA:</strong> requires setup of contexts, memory allocation (<code>cudaMalloc</code>), memory copy (<code>cudaMemcpy</code>), kernel launch parameters, and error checking.</p><h3 id="neural-network-training" tabindex="-1">Neural Network Training <a class="header-anchor" href="#neural-network-training" aria-label="Permalink to &quot;Neural Network Training&quot;">​</a></h3><p><strong>Vex:</strong></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn train_step(x: [f32], y: [f32], weights: &amp;Weights!, lr: f32) {</span></span>
<span class="line"><span>    let loss = @{</span></span>
<span class="line"><span>        let pred = forward(x, $param(weights))</span></span>
<span class="line"><span>        -$sum(y * $log(pred))</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    weights -= lr * $grad(loss)</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>This snippet handles forward pass, backpropagation, and weight update in a single, readable block.</p>`,18)])])}const h=e(i,[["render",l]]);export{m as __pageData,h as default};
